"use client"

import { useEffect, useMemo, useState } from "react"

type JobResponse = {
  job_id?: string
  status?: string
  file_url?: string
  [key: string]: any
}

type GalleryItem = {
  name: string
  url: string
  extension: string
  size_bytes: number
  modified_ts: number
}

export default function Page() {
  const [topic, setTopic] = useState("How to make money with AI in 2026")
  const [mode, setMode] = useState("product")
  const [jobId, setJobId] = useState("")
  const [job, setJob] = useState<JobResponse | null>(null)
  const [loading, setLoading] = useState(false)
  const [gallery, setGallery] = useState<GalleryItem[]>([])

  const endpoint = useMemo(() => {
    if (mode === "shorts") return "/api/shorts-pack"
    if (mode === "youtube") return "/api/youtube-pack"
    return "/api/product-pack"
  }, [mode])

  async function loadGallery() {
    const res = await fetch("/api/gallery", { cache: "no-store" })
    const data = await res.json()
    setGallery(data.items || [])
  }

  async function generate() {
    setLoading(true)
    setJob(null)
    setJobId("")

    const res = await fetch(endpoint, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        topic,
        niche: "Make Money Online",
        tone: "Premium",
        buyer: "Beginners starting from zero",
        promise: "get results faster",
        bonus: "templates and prompts",
        notes: "Keep it practical and premium",
        duration_seconds: 35,
      }),
    })

    const data = await res.json()
    setJob(data)
    if (data.job_id) {
      setJobId(data.job_id)
    } else {
      setLoading(false)
      loadGallery()
    }
  }

  useEffect(() => {
    loadGallery()
  }, [])

  useEffect(() => {
    if (!jobId) return

    const timer = setInterval(async () => {
      const res = await fetch(`/api/job/${jobId}`, { cache: "no-store" })
      const data = await res.json()
      setJob(data)

      if (data.status && ["done", "failed", "completed"].includes(String(data.status).toLowerCase())) {
        clearInterval(timer)
        setLoading(false)
        loadGallery()
      }
    }, 2000)

    return () => clearInterval(timer)
  }, [jobId])

  return (
    <main style={{ maxWidth: 980, margin: "0 auto", padding: 24, fontFamily: "Arial, sans-serif" }}>
      <h1 style={{ fontSize: 36, marginBottom: 8 }}>Zerenthis</h1>
      <p style={{ opacity: 0.8, marginBottom: 24 }}>Generate digital product packs, shorts, and YouTube assets from one simple console.</p>

      <div style={{ display: "grid", gap: 12, marginBottom: 24 }}>
        <input
          value={topic}
          onChange={(e) => setTopic(e.target.value)}
          placeholder="Enter a topic"
          style={{ padding: 12, fontSize: 16, borderRadius: 10, border: "1px solid #ccc" }}
        />

        <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
          <button onClick={() => setMode("product")} style={{ padding: "10px 14px", borderRadius: 10 }}>{mode === "product" ? "✓ " : ""}Product Pack</button>
          <button onClick={() => setMode("shorts")} style={{ padding: "10px 14px", borderRadius: 10 }}>{mode === "shorts" ? "✓ " : ""}Shorts Pack</button>
          <button onClick={() => setMode("youtube")} style={{ padding: "10px 14px", borderRadius: 10 }}>{mode === "youtube" ? "✓ " : ""}YouTube Pack</button>
          <button onClick={generate} disabled={loading || !topic.trim()} style={{ padding: "10px 14px", borderRadius: 10 }}>
            {loading ? "Generating..." : "Generate"}
          </button>
        </div>
      </div>

      {job && (
        <section style={{ marginBottom: 32, padding: 16, border: "1px solid #ddd", borderRadius: 12 }}>
          <h2 style={{ marginTop: 0 }}>Latest Result</h2>
          <pre style={{ whiteSpace: "pre-wrap", overflowX: "auto" }}>{JSON.stringify(job, null, 2)}</pre>
        </section>
      )}

      <section>
        <h2>Output Gallery</h2>
        <div style={{ display: "grid", gap: 12 }}>
          {gallery.map((item) => (
            <a key={item.name} href={item.url} target="_blank" rel="noreferrer" style={{ padding: 14, border: "1px solid #ddd", borderRadius: 12, textDecoration: "none", color: "inherit" }}>
              <strong>{item.name}</strong>
              <div style={{ opacity: 0.7, marginTop: 4 }}>{item.extension} • {Math.round(item.size_bytes / 1024)} KB</div>
            </a>
          ))}
        </div>
      </section>
    </main>
  )
}

