    _validate_steps(p.get("steps", []))

    backups: list[tuple[Path, Path]] = []
    created: list[Path] = []

    try:
        for s in p["steps"]:
            path = _normalize_path(s["path"])

            if s["action"] == "create_file":
                path.parent.mkdir(parents=True, exist_ok=True)
                if path.exists():
                    b = backup(path)
                    if b:
                        backups.append((path, b))
                else:
                    created.append(path)
                path.write_text(s.get("content", ""), encoding="utf-8")

            elif s["action"] == "edit_file":
                if not path.exists():
                    raise FileNotFoundError(f"missing file: {s['path']}")
                original = path.read_text(encoding="utf-8", errors="ignore")
                find_text = s["find"]
                replace_text = s["replace"]

                if find_text not in original:
                    raise ValueError(f"find text not found in: {s['path']}")

                b = backup(path)
                if b:
                    backups.append((path, b))

                updated = original.replace(find_text, replace_text, 1)
                if updated == original:
                    raise ValueError(f"edit produced no change for: {s['path']}")

                path.write_text(updated, encoding="utf-8")

            elif s["action"] == "delete_file":
                if not path.exists():
                    raise FileNotFoundError(f"missing file: {s['path']}")
                b = backup(path)
                if b:
                    backups.append((path, b))
                path.unlink()

        if not verify():
            raise RuntimeError("verification failed")

        p["status"] = "applied"
        p["applied_at"] = time.time()
        p["result"] = {
            "ok": True,
            "applied_steps": len(p.get("steps", [])),
            "backup_count": len(backups),
            "created_count": len(created),
        }
        save(d)
        return {
            "ok": True,
            "id": pid,
            "status": "applied",
            "applied_steps": len(p.get("steps", [])),
            "backups": [str(b.relative_to(ROOT)) for _, b in backups],
            "created": [str(c.relative_to(ROOT)) for c in created],
        }
    except Exception as e:
        rollback_errors: list[str] = []

        for path in created:
            try:
                if path.exists():
                    path.unlink()
            except Exception as re:
                rollback_errors.append(f"failed removing created file {path}: {re}")

        for path, backup_path in reversed(backups):
            try:
                path.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(backup_path, path)
            except Exception as re:
                rollback_errors.append(f"failed restoring {path} from {backup_path}: {re}")

        p["status"] = "failed"
        p["failed_at"] = time.time()
        p["error"] = str(e)
        if rollback_errors:
            p["rollback_errors"] = rollback_errors
        save(d)

        return {
            "ok": False,
            "error": str(e),
            "status": "failed",
            "rollback_errors": rollback_errors,
