        counts[asset_kind] = counts.get(asset_kind, 0) + 1

        if kind and asset_kind != kind:
            continue

        items.append(
            {
                "name": path.name,
                "size_bytes": path.stat().st_size,
                "modified_ts": path.stat().st_mtime,
                "url": f"/api/file/{path.name}",
                "extension": path.suffix.lower(),
                "kind": asset_kind,
                "is_downloadable": asset_kind in {"product", "video", "image"},
            }
        )

    return {
        "items": items[:limit],
        "total_visible": len(items),
        "counts": counts,
        "filters": {
            "kind": kind or None,
            "limit": limit,
        },
    }

