def _assess_proposal_risk(title, reason, steps):
    title_l = title.lower()
    reason_l = reason.lower()
    risks = []
    score = 0

    if len(steps) >= 5:
        score += 10
        risks.append("multi_step_change")

    touched_product = False
    touched_runtime = False
    touched_ui = False

    for step in steps:
        action = step.get("action")
        path = str(step.get("path", ""))
        path_l = path.lower()

        if action == "delete_file":
            score += 35
            risks.append(f"delete:{path}")

        if path_l.endswith("main.py") or path_l.endswith("routes.py"):
            score += 15
            touched_runtime = True

        if "/engine/" in path_l or path_l.startswith("backend/engine/"):
            score += 10
            touched_product = True

        if path_l.endswith("page.tsx") or path_l.endswith("layout.tsx") or path_l.endswith("global.css"):
            score += 8
            touched_ui = True

        if action == "create_file" and len(step.get("content", "")) > 50000:
            score += 20
            risks.append(f"large_create:{path}")

        if action == "edit_file" and len(step.get("replace", "")) > 30000:
            score += 12
            risks.append(f"large_edit:{path}")

    if touched_product and touched_runtime:
        score += 10
        risks.append("cross_layer_product_runtime_change")

    if touched_runtime and touched_ui:
        score += 8
        risks.append("cross_layer_ui_runtime_change")

    if "monetiz" in reason_l or "revenue" in reason_l or "pricing" in reason_l:
        score += 3

    if score >= 60:
        level = "high"
    elif score >= 25:
        level = "medium"
    else:
        level = "low"

    return {"score": score, "level": level, "flags": risks}


def propose(title, reason, steps):
    if not isinstance(title, str) or not title.strip():
        raise ValueError("title is required")
    if not isinstance(reason, str) or len(reason.strip()) < 10:
        raise ValueError("reason must be at least 10 characters")
    _validate_steps(steps)
    title = title.strip()
    reason = reason.strip()
    d = load()
    fingerprint = _fingerprint(title, steps)

    for existing in d:
        if existing.get("fingerprint") == fingerprint and existing.get("status") in {"pending", "approved", "applied"}:
            return existing

    risk = _assess_proposal_risk(title, reason, steps)

    p = {
        "id": new_id(),
        "title": title,
        "reason": reason,
        "steps": steps,
        "status": "pending",
        "fingerprint": fingerprint,
        "risk": risk,
        "created_at": int(time.time())
    }
    d.append(p)
    save(d)
    return p

