def load():
    if not FILE.exists():
        return []
    try:
        return json.loads(FILE.read_text(encoding="utf-8"))
    except:
        return []

def save(d):
    FILE.write_text(json.dumps(d, indent=2), encoding="utf-8")

def new_id():
    return f"prop_{int(time.time())}_{uuid.uuid4().hex[:6]}"

def propose(title, reason, steps):
    p = {
        "id": new_id(),
        "title": title,
        "reason": reason,
        "steps": steps,
        "status": "pending"
    }
    d = load()
    d.append(p)
    save(d)
    return p

def pending():
    return [x for x in load() if x.get("status") == "pending"]

def approve(pid):
    d = load()
    for x in d:
        if x["id"] == pid:
            x["status"] = "approved"
    save(d)

def reject(pid):
    d = load()
    for x in d:
        if x["id"] == pid:
            x["status"] = "rejected"
    save(d)

def backup(path):
