BACKUPS = DATA / "backups"
FILE = DATA / "proposals.json"
EXECUTION_LOG = DATA / "execution_log.json"

DATA.mkdir(parents=True, exist_ok=True)
BACKUPS.mkdir(parents=True, exist_ok=True)

PROTECTED = {".env", ".git", "node_modules", "venv", "backend/data"}
ALLOWED_ACTIONS = {"create_file", "edit_file", "delete_file"}


def load():
    if not FILE.exists():
        return []
    try:
        return json.loads(FILE.read_text(encoding="utf-8"))
    except:
        return []


def save(d):
    FILE.write_text(json.dumps(d, indent=2), encoding="utf-8")


def _load_execution_log():
    if not EXECUTION_LOG.exists():
        return []
    try:
        data = json.loads(EXECUTION_LOG.read_text(encoding="utf-8"))
        return data if isinstance(data, list) else []
    except:
        return []


def _save_execution_log(items):
    EXECUTION_LOG.write_text(json.dumps(items, indent=2), encoding="utf-8")


def _append_execution_log(item):
    items = _load_execution_log()
    items.append(item)
    _save_execution_log(items)


def new_id():
    return f"prop_{int(time.time())}_{uuid.uuid4().hex[:6]}"


def summarize_steps(steps):
    action_counts = {}
    touched_paths = []
    for step in steps or []:
        action = step.get("action", "unknown")
        action_counts[action] = action_counts.get(action, 0) + 1
        path = step.get("path")
        if path and path not in touched_paths:
            touched_paths.append(path)
    return {
        "step_count": len(steps or []),
        "action_counts": action_counts,
        "touched_paths": touched_paths,
    }


def assess_proposal_risk(steps):
    summary = summarize_steps(steps)
    reasons = []
    level = "low"

    for path in summary["touched_paths"]:
        if any(blocked in path for blocked in PROTECTED):
            reasons.append(f"Touches protected path: {path}")
            level = "high"
        if path.endswith("main.py") or path.endswith("routes.py"):
            reasons.append(f"Touches runtime-critical file: {path}")
            if level != "high":
                level = "medium"

    if summary["action_counts"].get("delete_file", 0) > 0:
        reasons.append("Contains file deletion")
        if level != "high":
            level = "medium"

    if summary["step_count"] >= 5 and level == "low":
        reasons.append("Large multi-step proposal")
        level = "medium"

    return {
        "level": level,
        "reasons": reasons,
    }


def _validate_steps(steps):
    if not isinstance(steps, list) or not steps:
        raise ValueError("steps must be a non-empty list")

    for idx, step in enumerate(steps, start=1):
        if not isinstance(step, dict):
            raise ValueError(f"step {idx} must be an object")
        action = step.get("action")
        path = step.get("path")
        if action not in ALLOWED_ACTIONS:
            raise ValueError(f"step {idx} has invalid action")
        if not isinstance(path, str) or not path.strip():
            raise ValueError(f"step {idx} must include a valid path")
        if any(blocked in path for blocked in PROTECTED):
            raise ValueError(f"step {idx} touches protected path")
        if action == "edit_file":
            if "find" not in step or "replace" not in step:
                raise ValueError(f"step {idx} must include find and replace")
        if action == "create_file" and "content" not in step:
            raise ValueError(f"step {idx} must include content")

    return True


def validate_proposal_payload(title, reason, steps):
    if not isinstance(title, str) or len(title.strip()) < 3:
        raise ValueError("title must be at least 3 characters")
    if not isinstance(reason, str) or len(reason.strip()) < 10:
        raise ValueError("reason must be at least 10 characters")

    _validate_steps(steps)
    summary = summarize_steps(steps)
    risk = assess_proposal_risk(steps)
    fingerprint_source = json.dumps({"title": title.strip(), "reason": reason.strip(), "steps": steps}, sort_keys=True)
    fingerprint = hashlib.sha256(fingerprint_source.encode("utf-8")).hexdigest()[:16]

    return {
        "summary": summary,
        "risk": risk,
        "fingerprint": fingerprint,
    }


