    count = kwargs.get("count", 3)
    count = max(1, min(int(count or 3), 10))

    results = []
    base_topic = (kwargs.get("topic") or "Digital Product").strip()

    for i in range(count):
        variant_kwargs = dict(kwargs)
        if count > 1:
            variant_kwargs["topic"] = f"{base_topic} Variant {i + 1}"
        else:
            variant_kwargs["topic"] = base_topic

        results.append(build_product_pack(**variant_kwargs))

    return {
        "count": count,
        "items": results,
    }

